use fusion::runtime::{Scheduler, Task, WorkQueue};
use fusion::sync::AtomicUsize;

struct TaskScheduler {
    num_workers: usize,
    queue: WorkQueue<Task>,
    completed: AtomicUsize
}

impl TaskScheduler {
    fn new(num_workers: usize) -> Self {
        TaskScheduler {
            num_workers,
            queue: WorkQueue::new(),
            completed: AtomicUsize::new(0)
        }
    }

    async fn schedule(&self, task: Task) {
        self.queue.push(task).await;
    }

    async fn run(&self) {
        let workers: Vec<_> = (0..self.num_workers)
            .map(|_| spawn(self.worker_loop()))
            .collect();

        join_all(workers).await;
    }

    async fn worker_loop(&self) {
        loop {
            match self.queue.pop().await {
                Some(task) => {
                    task.execute().await;
                    self.completed.fetch_add(1, Ordering::SeqCst);
                },
                None => break
            }
        }
    }
}

