use fusion::ws::{WebSocket, Message, ConnectionId};
use fusion::sync::{Arc, Mutex};
use fusion::collections::HashMap;

struct ChatServer {
    connections: Arc<Mutex<HashMap<ConnectionId, WebSocket>>>
}

impl ChatServer {
    fn new() -> Self {
        ChatServer {
            connections: Arc::new(Mutex::new(HashMap::new()))
        }
    }

    async fn handle_connection(&self, ws: WebSocket, id: ConnectionId) {
        self.connections.lock().await.insert(id, ws.clone());

        loop {
            match ws.receive().await {
                Ok(Message::Text(text)) => {
                    self.broadcast(&text, id).await;
                },
                Ok(Message::Close) => {
                    self.connections.lock().await.remove(&id);
                    break;
                },
                Err(e) => {
                    eprintln!("WebSocket error: {}", e);
                    break;
                }
            }
        }
    }

    async fn broadcast(&self, message: &str, sender_id: ConnectionId) {
        let connections = self.connections.lock().await;

        for (id, ws) in connections.iter() {
            if *id != sender_id {
                let _ = ws.send(Message::Text(message.to_string())).await;
            }
        }
    }

    async fn run(&self, addr: &str) {
        let listener = WebSocket::bind(addr).await.unwrap();

        loop {
            let (ws, id) = listener.accept().await.unwrap();
            let server = self.clone();

            spawn(async move {
                server.handle_connection(ws, id).await;
            });
        }
    }
}

const fn fibonacci(n: usize) -> usize {
    match n {
        0 => 0,
        1 => 1,
        _ => fibonacci(n - 1) + fibonacci(n - 2)
    }
}

struct FibArray<const N: usize> {
    values: [usize; N]
}

impl<const N: usize> FibArray<N> {
    const fn new() -> Self {
        let mut values = [0; N];
        let mut i = 0;
        while i < N {
            values[i] = fibonacci(i);
            i += 1;
        }
        FibArray { values }
    }
}

