use fusion::http::{Request, Response, Next};

type Middleware = fn(Request, Next) -> Response;
type Next = fn(Request) -> Response;

struct Pipeline {
    middlewares: Vec<Middleware>,
    handler: fn(Request) -> Response
}

impl Pipeline {
    fn new(handler: fn(Request) -> Response) -> Self {
        Pipeline {
            middlewares: Vec::new(),
            handler
        }
    }

    fn use_middleware(mut self, middleware: Middleware) -> Self {
        self.middlewares.push(middleware);
        return self;
    }

    fn execute(&self, request: Request) -> Response {
        let mut index = 0;
        let middlewares = &self.middlewares;
        let handler = self.handler;

        fn next(request: Request, middlewares: &[Middleware], handler: fn(Request) -> Response, index: &mut usize) -> Response {
            if *index >= middlewares.len() {
                return handler(request);
            }

            let middleware = middlewares[*index];
            *index += 1;

            return middleware(request, |req| next(req, middlewares, handler, index));
        }

        return next(request, middlewares, handler, &mut index);
    }
}

// Example middlewares
fn logger(req: Request, next: Next) -> Response {
    println!("[{}] {}", req.method, req.path);
    return next(req);
}

fn auth(req: Request, next: Next) -> Response {
    if req.headers.get("Authorization").is_none() {
        return Response::unauthorized();
    }
    return next(req);
}

// Usage
let pipeline = Pipeline::new(|req| Response::ok().body("Hello"))
    .use_middleware(logger)
    .use_middleware(auth);

@manual_memory
struct PoolAllocator {
    pool: *mut u8,
    block_size: usize,
    num_blocks: usize,
    free_list: Vec<usize>
}

impl PoolAllocator {
    fn new(block_size: usize, num_blocks: usize) -> Self {
        unsafe {
            let total_size = block_size * num_blocks;
            let layout = Layout::from_size_align(total_size, block_size).unwrap();
            let pool = alloc(layout);

            let mut free_list = Vec::with_capacity(num_blocks);
            for i in 0..num_blocks {
                free_list.push(i);
            }

            PoolAllocator {
                pool,
                block_size,
                num_blocks,
                free_list
            }
        }
    }

    fn allocate(&mut self) -> Option<*mut u8> {
        if let Some(index) = self.free_list.pop() {
            unsafe {
                let offset = index * self.block_size;
                let ptr = self.pool.add(offset);
                return Some(ptr);
            }
        }
        return None;
    }

    fn deallocate(&mut self, ptr: *mut u8) {
        unsafe {
            let offset = ptr.offset_from(self.pool) as usize;
            let index = offset / self.block_size;
            self.free_list.push(index);
        }
    }
}

impl Drop for PoolAllocator {
    fn drop(&mut self) {
        unsafe {
            let total_size = self.block_size * self.num_blocks;
            let layout = Layout::from_size_align(total_size, self.block_size).unwrap();
            dealloc(self.pool, layout);
        }
    }
}

